import { readFile } from "node:fs/promises";
import path from "node:path";
import { readAppEnv } from "../app/env";
import { createDbConnection } from "../db";
import { EvaluationRepository } from "../modules/evaluations/evaluation.repository";
import { EvaluationService } from "../modules/evaluations/evaluation.service";
import { ProjectRepository } from "../modules/projects/project.repository";
import { ProjectService } from "../modules/projects/project.service";
import {
	projectProfileInputSchema,
	type ProjectProfile,
	type ProjectProfileInput,
} from "../../shared/schemas/project.schema";
import type {
	EvaluationBundle,
	EvaluationResponse,
	JudgeSelection,
} from "../../shared/schemas/evaluation.schema";
import { defaultCodexJudgeSelection } from "../modules/llm/judge-client";

type ParsedArgs = {
	project?: string;
	profile?: string;
	json: boolean;
	judge: JudgeSelection;
};

function readRequiredValue(
	argv: string[],
	index: number,
	flag: string,
): string {
	const value = argv[index + 1];
	if (!value || value.startsWith("--")) {
		throw new Error(`Missing value for ${flag}.`);
	}
	return value;
}

export function parseEvaluatorArgs(argv: string[]): ParsedArgs {
	const parsed: ParsedArgs = {
		json: false,
		judge: defaultCodexJudgeSelection,
	};
	for (let index = 0; index < argv.length; index += 1) {
		const arg = argv[index];
		if (arg === "--json") {
			parsed.json = true;
			continue;
		}
		if (arg === "--project") {
			parsed.project = readRequiredValue(argv, index, "--project");
			index += 1;
			continue;
		}
		if (arg === "--profile") {
			parsed.profile = readRequiredValue(argv, index, "--profile");
			index += 1;
			continue;
		}
		throw new Error(`Unknown argument: ${arg}`);
	}
	if (!parsed.project) {
		throw new Error("Missing required --project <path> argument.");
	}
	return parsed;
}

export async function runEvaluatorCli(fn: () => Promise<void>): Promise<void> {
	try {
		await fn();
	} catch (error) {
		console.error(error instanceof Error ? error.message : String(error));
		process.exitCode = 1;
	}
}

async function readProfileFile(
	profilePath: string,
): Promise<Partial<ProjectProfileInput>> {
	const text = await readFile(profilePath, "utf8");
	const parsed = JSON.parse(text) as unknown;
	if (!parsed || typeof parsed !== "object") {
		throw new Error("Profile file must contain a JSON object.");
	}
	return parsed;
}

export async function loadProjectInput(
	args: ParsedArgs,
): Promise<ProjectProfileInput> {
	const rootPath = path.resolve(args.project ?? ".");
	const fromFile = args.profile
		? await readProfileFile(path.resolve(args.profile))
		: {};
	const packageJsonPath = path.join(rootPath, "package.json");
	let fallbackName = path.basename(rootPath);
	try {
		const packageJson = JSON.parse(await readFile(packageJsonPath, "utf8")) as {
			name?: string;
		};
		fallbackName = packageJson.name ?? fallbackName;
	} catch {
		// The bundle builder records missing package.json; CLI profile loading can continue.
	}
	return projectProfileInputSchema.parse({
		name: fallbackName,
		ideal:
			"このプロジェクトが、対象ユーザーに明確な価値を提供し、実装・検証・文書・agent usability が揃った状態。",
		...fromFile,
		rootPath,
	});
}

export async function withEvaluatorServices<T>(
	fn: (services: {
		projectService: ProjectService;
		evaluationService: EvaluationService;
	}) => Promise<T>,
): Promise<T> {
	const env = readAppEnv();
	const connection = createDbConnection(env.databaseUrl);
	try {
		const projectService = new ProjectService(
			new ProjectRepository(connection.db),
		);
		const evaluationService = new EvaluationService(
			projectService,
			new EvaluationRepository(connection.db),
		);
		return await fn({ projectService, evaluationService });
	} finally {
		connection.client.close();
	}
}

export async function findOrCreateCliProject(
	projectService: ProjectService,
	args: ParsedArgs,
): Promise<ProjectProfile> {
	const projectInput = await loadProjectInput(args);
	return projectService.findOrCreate(projectInput);
}

export function printBundle(bundle: EvaluationBundle, json: boolean): void {
	if (json) {
		console.log(JSON.stringify({ bundle }, null, 2));
		return;
	}
	console.log(`Bundle: ${bundle.id}`);
	console.log(`Project: ${bundle.projectId}`);
	console.log(`Evidence Level: ${bundle.evidenceLevel}`);
	console.log(`Inputs: ${Object.keys(bundle.inputs).join(", ")}`);
	console.log(`Source Files: ${bundle.inputs.sourceFiles.length}`);
	console.log(`Verification Runs: ${bundle.inputs.verificationRuns.length}`);
	if (bundle.missingInputs.length > 0) {
		console.log(`Missing Inputs: ${bundle.missingInputs.join(", ")}`);
	}
}

export function printEvaluation(
	result: EvaluationResponse,
	json: boolean,
): void {
	if (json) {
		console.log(JSON.stringify(result, null, 2));
		return;
	}
	const { evaluation, improvements } = result;
	console.log(`Evaluation: ${evaluation.id}`);
	console.log(`Score: ${evaluation.score} / ${evaluation.idealScore}`);
	console.log(`Confidence: ${evaluation.overallConfidence}`);
	console.log(`Evidence Level: ${evaluation.evidenceLevel}`);
	if (evaluation.scoreDelta !== undefined) {
		console.log(`Score Delta: ${evaluation.scoreDelta}`);
	}
	if (evaluation.confidenceDelta !== undefined) {
		console.log(`Confidence Delta: ${evaluation.confidenceDelta}`);
	}
	console.log("\nVerification Runs:");
	for (const run of result.bundle.inputs.verificationRuns) {
		console.log(
			`- ${run.name}: ${run.status} (${run.durationMs}ms, exit ${run.exitCode ?? "n/a"})`,
		);
	}
	console.log("\nSource Checks:");
	for (const inspection of evaluation.sourceInspections) {
		console.log(
			`- ${inspection.title}: ${inspection.status} (${inspection.files.length} files)`,
		);
	}
	console.log("\nTop Gaps:");
	for (const gap of evaluation.gapsTo100.slice(0, 5)) {
		console.log(
			`- ${gap.title} (${gap.kind}, +${gap.expectedScoreGain} score, +${gap.expectedConfidenceGain} confidence)`,
		);
	}
	console.log("\nNext Improvements:");
	for (const improvement of improvements.slice(0, 5)) {
		console.log(
			`${improvement.priority}. ${improvement.title} (${improvement.taskType})`,
		);
	}
}

import { randomUUID } from "node:crypto";
import { execFile } from "node:child_process";
import type { Dirent } from "node:fs";
import { readdir, readFile } from "node:fs/promises";
import path from "node:path";
import { promisify } from "node:util";
import {
	evaluationBundleSchema,
	type EvaluationBundle,
	type ProjectValueEvaluation,
	type SourceFileEvidence,
	type SourceFileRole,
	type SourceInspectionCheck,
	type SourceInspectionCheckId,
	type VerificationRun,
} from "../../../shared/schemas/evaluation.schema";
import type { ProjectProfile } from "../../../shared/schemas/project.schema";

const execFileAsync = promisify(execFile);

const IGNORED_TREE_ENTRIES = new Set([
	".git",
	".DS_Store",
	".env",
	".env.local",
	".env.test",
	"node_modules",
	"dist",
	"dist-web",
	"coverage",
	".vite",
	".next",
	".turbo",
	"sqlite.db",
]);

const MAX_TEXT_CHARS = 24_000;
const MAX_SOURCE_FILE_CHARS = 16_000;
const MAX_SOURCE_FILES = 18;
const MAX_SOURCE_FILES_PER_ROLE = 4;
const MAX_TREE_ENTRIES = 360;
const MAX_TREE_DEPTH = 4;
const MAX_VERIFICATION_OUTPUT_CHARS = 12_000;
const VERIFICATION_TIMEOUT_MS = 120_000;

function compactSingleLine(value: string): string {
	return value.replace(/\s+/g, " ").trim();
}

function buildSystemContext(project: ProjectProfile, projectRoot: string) {
	return {
		targetProjectName: project.name,
		targetProjectRoot: projectRoot,
		projectIdeal: project.ideal,
		primaryAudience: project.primaryAudience,
		targetWorkflow: project.targetWorkflow,
		nonGoals: project.nonGoals,
	};
}

function buildSourceInspectionPlan(
	project: ProjectProfile,
): SourceInspectionCheck[] {
	const targetWorkflow = compactSingleLine(project.targetWorkflow);
	const primaryAudience = compactSingleLine(project.primaryAudience);
	return [
		{
			id: "entrypoint-flow",
			title: "主要ワークフローへの実行経路",
			objective: `${targetWorkflow} を開始する UI、API、CLI などの入口が、中核処理へ正しく接続されているかを確認する。`,
			requiredRoles: ["entrypoint", "interface-boundary", "core-logic"],
		},
		{
			id: "domain-logic",
			title: "対象プロジェクトの中核ロジック",
			objective:
				"README、Project Ideal、対象ワークフローで約束している価値が、実装上の中核ロジックとして存在するかを確認する。",
			requiredRoles: ["core-logic", "data-model"],
		},
		{
			id: "data-persistence",
			title: "状態管理と再現性",
			objective:
				"対象ワークフローに必要な状態、設定、保存データ、再実行時の一貫性が適切に扱われているかを確認する。",
			requiredRoles: ["data-model", "core-logic"],
		},
		{
			id: "external-boundary",
			title: "外部境界と失敗時挙動",
			objective:
				"認証、外部 API、ファイルシステム、コマンド実行、LLM などの境界が明示され、失敗時に対象ワークフローを誤魔化さないかを確認する。",
			requiredRoles: ["external-boundary", "interface-boundary"],
		},
		{
			id: "verification-signal",
			title: "検証可能性",
			objective:
				"テスト、verify、build など、対象プロジェクトの主張を確認できる検証経路があるかを確認する。",
			requiredRoles: ["test-signal", "entrypoint"],
		},
		{
			id: "agent-output-contract",
			title: "利用者へ渡る操作・出力契約",
			objective: `${primaryAudience} が ${targetWorkflow} を実行・確認・改善できる粒度の操作、出力、エラー、文書が揃っているかを確認する。`,
			requiredRoles: ["core-logic", "data-model", "interface-boundary"],
		},
	];
}

const sourceFileExtensions = new Set([
	".ts",
	".tsx",
	".js",
	".jsx",
	".mjs",
	".cjs",
	".py",
	".rs",
	".go",
	".java",
	".kt",
	".swift",
	".rb",
	".php",
]);

async function readOptionalText(
	root: string,
	filename: string,
	missingInputs: string[],
): Promise<string | undefined> {
	try {
		const text = await readFile(path.join(root, filename), "utf8");
		return text.slice(0, MAX_TEXT_CHARS);
	} catch {
		missingInputs.push(filename);
		return undefined;
	}
}

async function readPackageJson(
	root: string,
	missingInputs: string[],
): Promise<Record<string, unknown> | undefined> {
	const text = await readOptionalText(root, "package.json", missingInputs);
	if (!text) return undefined;
	try {
		return JSON.parse(text) as Record<string, unknown>;
	} catch {
		missingInputs.push("package.json:invalid-json");
		return undefined;
	}
}

function packageScripts(
	packageJson: Record<string, unknown> | undefined,
): Record<string, string> {
	const scripts = packageJson?.scripts;
	if (!scripts || typeof scripts !== "object") return {};
	return Object.fromEntries(
		Object.entries(scripts).filter(
			(entry): entry is [string, string] => typeof entry[1] === "string",
		),
	);
}

function trimVerificationOutput(value: string): string {
	if (value.length <= MAX_VERIFICATION_OUTPUT_CHARS) return value;
	return value.slice(-MAX_VERIFICATION_OUTPUT_CHARS);
}

function selectVerificationScripts(
	scripts: Record<string, string>,
): Array<{ name: string; command: string[] }> {
	if (scripts.verify) {
		return [{ name: "verify", command: ["bun", "run", "verify"] }];
	}
	return ["typecheck", "test", "build"]
		.filter((name) => scripts[name])
		.map((name) => ({ name, command: ["bun", "run", name] }));
}

async function runVerificationCommand(
	root: string,
	name: string,
	command: string[],
): Promise<VerificationRun> {
	const startedAt = Date.now();
	try {
		const { stdout, stderr } = await execFileAsync(
			command[0],
			command.slice(1),
			{
				cwd: root,
				timeout: VERIFICATION_TIMEOUT_MS,
				maxBuffer: MAX_VERIFICATION_OUTPUT_CHARS * 4,
			},
		);
		return {
			name,
			command,
			status: "passed",
			exitCode: 0,
			durationMs: Date.now() - startedAt,
			stdout: trimVerificationOutput(stdout),
			stderr: trimVerificationOutput(stderr),
		};
	} catch (error) {
		const commandError = error as {
			code?: number | string;
			killed?: boolean;
			signal?: string;
			stdout?: string;
			stderr?: string;
		};
		const timedOut =
			commandError.killed === true || commandError.signal === "SIGTERM";
		return {
			name,
			command,
			status: timedOut ? "timed-out" : "failed",
			exitCode:
				typeof commandError.code === "number" ? commandError.code : null,
			durationMs: Date.now() - startedAt,
			stdout: trimVerificationOutput(commandError.stdout ?? ""),
			stderr: trimVerificationOutput(commandError.stderr ?? ""),
		};
	}
}

async function runVerificationCommands(
	root: string,
	scripts: Record<string, string>,
): Promise<VerificationRun[]> {
	const selected = selectVerificationScripts(scripts);
	const runs: VerificationRun[] = [];
	for (const item of selected) {
		runs.push(await runVerificationCommand(root, item.name, item.command));
	}
	return runs;
}

async function collectTree(
	root: string,
	current: string,
	depth: number,
	entries: string[],
): Promise<void> {
	if (entries.length >= MAX_TREE_ENTRIES || depth > MAX_TREE_DEPTH) return;
	let dirents: Dirent[];
	try {
		dirents = await readdir(path.join(root, current), { withFileTypes: true });
	} catch {
		return;
	}
	for (const dirent of dirents.sort((a, b) => a.name.localeCompare(b.name))) {
		if (entries.length >= MAX_TREE_ENTRIES) return;
		if (IGNORED_TREE_ENTRIES.has(dirent.name)) continue;
		if (dirent.name.endsWith(".sqlite") || dirent.name.endsWith(".sqlite3")) {
			continue;
		}
		const relativePath = path.join(current, dirent.name);
		entries.push(dirent.isDirectory() ? `${relativePath}/` : relativePath);
		if (dirent.isDirectory()) {
			await collectTree(root, relativePath, depth + 1, entries);
		}
	}
}

function isLogicSourceFile(relativePath: string): boolean {
	const extension = path.extname(relativePath);
	if (!sourceFileExtensions.has(extension)) return false;
	if (relativePath.includes(".d.ts")) return false;
	if (relativePath.includes("/generated/")) return false;
	return (
		!relativePath.endsWith(".config.ts") && !relativePath.endsWith(".config.js")
	);
}

const domainKeywordStopWords = new Set([
	"and",
	"the",
	"for",
	"from",
	"with",
	"that",
	"this",
	"project",
	"users",
	"user",
	"items",
	"item",
	"manage",
	"create",
	"reliably",
	"through",
	"対象",
	"主要",
	"実行",
	"改善",
	"状態",
	"ユーザー",
	"プロジェクト",
]);

function projectDomainKeywords(project: ProjectProfile): Set<string> {
	const text = [
		project.name,
		project.ideal,
		project.primaryAudience,
		project.targetWorkflow,
		...project.nonGoals,
	].join(" ");
	const tokens = text
		.toLowerCase()
		.split(/[^a-z0-9一-龠ぁ-んァ-ヶー]+/u)
		.map((token) => token.trim())
		.filter((token) => token.length >= 3)
		.filter((token) => !domainKeywordStopWords.has(token));
	return new Set(tokens.slice(0, 16));
}

function hasDomainKeyword(
	normalizedPath: string,
	keywords: Set<string>,
): boolean {
	for (const keyword of keywords) {
		if (normalizedPath.includes(keyword)) return true;
	}
	return false;
}

function classifySourceFile(
	relativePath: string,
	keywords: Set<string>,
): SourceFileRole | null {
	const normalized = relativePath.toLowerCase();
	const basename = path.basename(normalized);
	if (
		normalized.includes(".test.") ||
		normalized.includes(".spec.") ||
		normalized.includes("__tests__/") ||
		normalized.includes("/test/")
	) {
		return "test-signal";
	}
	if (
		normalized.includes("llm") ||
		normalized.includes("codex") ||
		normalized.includes("client") ||
		normalized.includes("adapter") ||
		normalized.includes("provider") ||
		normalized.includes("auth") ||
		normalized.includes("middleware") ||
		normalized.includes("security")
	) {
		return "external-boundary";
	}
	if (
		normalized.includes("schema") ||
		normalized.includes("repository") ||
		normalized.includes("/db/") ||
		normalized.includes("model") ||
		normalized.includes("types")
	) {
		return "data-model";
	}
	if (
		normalized.includes("service") ||
		normalized.includes("domain") ||
		normalized.includes("usecase") ||
		normalized.includes("workflow") ||
		normalized.includes("pipeline") ||
		normalized.includes("evaluator") ||
		normalized.includes("judge") ||
		normalized.includes("generator") ||
		normalized.includes("builder") ||
		normalized.includes("engine")
	) {
		return "core-logic";
	}
	if (
		normalized.includes("/route") ||
		normalized.includes("routes/") ||
		normalized.includes("/api/") ||
		normalized.includes("/cli/") ||
		normalized.includes("/views/") ||
		normalized.includes("/pages/") ||
		normalized.includes("/components/") ||
		normalized.includes("controller") ||
		basename.includes("view") ||
		basename.includes("page") ||
		basename.includes("component") ||
		basename.includes("server")
	) {
		return "interface-boundary";
	}
	if (hasDomainKeyword(normalized, keywords)) {
		return relativePath.endsWith(".tsx") || relativePath.endsWith(".jsx")
			? "interface-boundary"
			: "core-logic";
	}
	if (
		basename === "main.ts" ||
		basename === "main.tsx" ||
		basename === "index.ts" ||
		basename === "index.tsx" ||
		basename === "app.ts" ||
		basename === "app.tsx"
	) {
		return "entrypoint";
	}
	return null;
}

function sourceCheckIdsForRole(
	role: SourceFileRole,
): SourceInspectionCheckId[] {
	const idsByRole: Record<SourceFileRole, SourceInspectionCheckId[]> = {
		entrypoint: ["entrypoint-flow", "verification-signal"],
		"interface-boundary": [
			"entrypoint-flow",
			"external-boundary",
			"agent-output-contract",
		],
		"core-logic": ["domain-logic", "data-persistence", "agent-output-contract"],
		"data-model": ["domain-logic", "data-persistence", "agent-output-contract"],
		"external-boundary": ["external-boundary"],
		"test-signal": ["verification-signal"],
	};
	return idsByRole[role];
}

function sourceFileReason(role: SourceFileRole): string {
	const reasons: Record<SourceFileRole, string> = {
		entrypoint:
			"実行入口として、対象ワークフローの中核処理へ接続される経路を確認するため。",
		"interface-boundary":
			"外部入力を受け取り対象ワークフローへ渡す境界を確認するため。",
		"core-logic":
			"Project Ideal に関わる中核ロジックと業務判断を確認するため。",
		"data-model":
			"対象ワークフローの状態、データ構造、保存形式の契約を確認するため。",
		"external-boundary":
			"LLM、Codex、認証、外部コマンドなどの境界と失敗時挙動を確認するため。",
		"test-signal": "対象プロジェクトの信頼度を支える検証経路を確認するため。",
	};
	return reasons[role];
}

function sortSourceCandidates(
	a: { path: string; role: SourceFileRole },
	b: { path: string; role: SourceFileRole },
): number {
	const roleRank: Record<SourceFileRole, number> = {
		"core-logic": 0,
		"interface-boundary": 1,
		"data-model": 2,
		"external-boundary": 3,
		entrypoint: 4,
		"test-signal": 5,
	};
	const roleDelta = roleRank[a.role] - roleRank[b.role];
	return roleDelta === 0 ? a.path.localeCompare(b.path) : roleDelta;
}

async function collectSourceFiles(
	root: string,
	repoTree: string[],
	project: ProjectProfile,
): Promise<SourceFileEvidence[]> {
	const keywords = projectDomainKeywords(project);
	const candidates = repoTree
		.filter((entry) => !entry.endsWith("/"))
		.filter(isLogicSourceFile)
		.map((entry) => ({
			path: entry,
			role: classifySourceFile(entry, keywords),
		}))
		.filter((candidate): candidate is { path: string; role: SourceFileRole } =>
			Boolean(candidate.role),
		)
		.sort(sortSourceCandidates);

	const roleCounts = new Map<SourceFileRole, number>();
	const selected: { path: string; role: SourceFileRole }[] = [];
	for (const candidate of candidates) {
		if (selected.length >= MAX_SOURCE_FILES) break;
		const count = roleCounts.get(candidate.role) ?? 0;
		if (count >= MAX_SOURCE_FILES_PER_ROLE) continue;
		selected.push(candidate);
		roleCounts.set(candidate.role, count + 1);
	}

	const sourceFiles: SourceFileEvidence[] = [];
	for (const candidate of selected) {
		try {
			const content = await readFile(path.join(root, candidate.path), "utf8");
			sourceFiles.push({
				path: candidate.path,
				role: candidate.role,
				checkIds: sourceCheckIdsForRole(candidate.role),
				reason: sourceFileReason(candidate.role),
				content: content.slice(0, MAX_SOURCE_FILE_CHARS),
				truncated: content.length > MAX_SOURCE_FILE_CHARS,
			});
		} catch {
			// Missing source files are already represented by the repo tree snapshot.
		}
	}
	return sourceFiles;
}

export async function buildEvaluationBundle(params: {
	project: ProjectProfile;
	projectRoot?: string;
	previousEvaluation?: ProjectValueEvaluation | null;
}): Promise<EvaluationBundle> {
	const projectRoot = path.resolve(
		params.projectRoot ?? params.project.rootPath,
	);
	const missingInputs: string[] = [];
	const readme = await readOptionalText(
		projectRoot,
		"README.md",
		missingInputs,
	);
	const llmContext = await readOptionalText(
		projectRoot,
		"LLM_CONTEXT.md",
		missingInputs,
	);
	const agents = await readOptionalText(
		projectRoot,
		"AGENTS.md",
		missingInputs,
	);
	const packageJson = await readPackageJson(projectRoot, missingInputs);
	const repoTree: string[] = [];
	await collectTree(projectRoot, "", 1, repoTree);
	if (repoTree.length === 0) {
		missingInputs.push("repo-tree");
	}
