import { randomUUID } from "node:crypto";
import type {
	EvaluationActivityEvent,
	EvaluationBundle,
	EvaluationResponse,
	JudgeRun,
	JudgeSelection,
	ProjectValueEvaluation,
} from "../../../shared/schemas/evaluation.schema";
import type { ProjectService } from "../projects/project.service";
import { judgeProjectValue as defaultJudgeProjectValue } from "../llm/judge-client";
import { buildEvaluationBundle } from "./bundle-builder";
import type { EvaluationRepository } from "./evaluation.repository";
import { generateImprovementRequests } from "./improvement-generator";
import { HttpError } from "../auth/errors";

export type EvaluationActivityEmitter = (
	event: Omit<EvaluationActivityEvent, "id" | "seq" | "createdAt">,
) => Promise<void> | void;

export type EvaluationActivityObserver = (
	event: EvaluationActivityEvent,
) => Promise<void> | void;

export type JudgeProjectValueFn = (params: {
	project: Awaited<ReturnType<ProjectService["get"]>>;
	bundle: EvaluationBundle;
	previousEvaluation?: ProjectValueEvaluation | null;
	judge?: JudgeSelection;
	emitActivity?: EvaluationActivityEmitter;
}) => Promise<{
	evaluation: ProjectValueEvaluation;
	rawOutput: unknown;
	judgeRun: JudgeRun;
}>;

export class EvaluationService {
	constructor(
		private readonly projects: ProjectService,
		private readonly evaluations: EvaluationRepository,
		private readonly judgeProjectValue: JudgeProjectValueFn = defaultJudgeProjectValue,
	) {}

	async evaluateProject(params: {
		projectId: string;
		projectRoot?: string;
		judge?: JudgeSelection;
		emitActivity?: EvaluationActivityObserver;
	}): Promise<EvaluationResponse> {
		const activityEvents: EvaluationActivityEvent[] = [];
		let seq = 0;
		const emit: EvaluationActivityEmitter = async (event) => {
			const activity = {
				id: randomUUID(),
				seq: seq++,
				createdAt: new Date().toISOString(),
				...event,
			};
			activityEvents.push(activity);
			await params.emitActivity?.(activity);
		};
		await emit({
			phase: "project",
			level: "info",
			source: "evaluator",
			message: "Loading project profile.",
		});
		const project = await this.projects.get(params.projectId);
		await emit({
			phase: "history",
			level: "info",
			source: "evaluator",
			message: "Loading previous evaluation.",
		});
		const previousEvaluation = await this.evaluations.findLatestEvaluation(
			project.id,
		);
		await emit({
			phase: "bundle",
			level: "info",
			source: "evaluator",
			message: "Building evaluation bundle and verification evidence.",
		});
		const bundle = await buildEvaluationBundle({
			project,
			projectRoot: params.projectRoot,
			previousEvaluation,
		});
		await emit({
			phase: "bundle",
			level: "checkpoint",
			source: "evaluator",
			message: `Bundle ready: ${bundle.inputs.sourceFiles.length} source files, ${bundle.inputs.verificationRuns.length} verification run(s).`,
			payload: {
				evidenceLevel: bundle.evidenceLevel,
				sourceFiles: bundle.inputs.sourceFiles.map((file) => file.path),
				verificationRuns: bundle.inputs.verificationRuns.map((run) => ({
					name: run.name,
					status: run.status,
					exitCode: run.exitCode,
					durationMs: run.durationMs,
				})),
			},
		});
		await emit({
			phase: "judge",
			level: "info",
			source: "evaluator",
			message: "Starting judge evaluation.",
			payload: { judge: params.judge },
		});
		const judged = await this.judgeProjectValue({
			project,
			bundle,
			previousEvaluation,
			judge: params.judge,
			emitActivity: emit,
		});
		await emit({
			phase: "save",
			level: "info",
			source: "evaluator",
			message: "Saving evaluation and generated improvement requests.",
		});
		const run = await this.evaluations.createEvaluationRun({
			bundle,
			evaluation: judged.evaluation,
			rawOutput: judged.rawOutput,
			improvements: generateImprovementRequests(judged.evaluation),
			activityEvents,
		});
		const persistedActivityCount = run.activityEvents.length;
		await emit({
			phase: "complete",
			level: "checkpoint",
			source: "evaluator",
			message: `Evaluation complete: ${run.evaluation.score} / ${run.evaluation.idealScore}.`,
			payload: {
				evaluationId: run.evaluation.id,
				score: run.evaluation.score,
				confidence: run.evaluation.overallConfidence,
			},
		});
		const pendingActivityEvents = activityEvents.slice(persistedActivityCount);
		await this.evaluations.createActivityEvents(
			run.evaluation.id,
			pendingActivityEvents,
		);
		return { ...run, judgeRun: judged.judgeRun, activityEvents };
	}

	async createBundle(params: {
		projectId: string;
		projectRoot?: string;
	}): Promise<EvaluationBundle> {
		const project = await this.projects.get(params.projectId);
		const previousEvaluation = await this.evaluations.findLatestEvaluation(
			project.id,
		);
		const bundle = await buildEvaluationBundle({
			project,
			projectRoot: params.projectRoot,
			previousEvaluation,
		});
		return this.evaluations.createBundle(bundle);
	}

	async getLatestEvaluation(
		projectId: string,
	): Promise<ProjectValueEvaluation> {
		const evaluation = await this.evaluations.findLatestEvaluation(projectId);
		if (!evaluation) {
			throw new HttpError(404, "Evaluation not found.");
		}
		return evaluation;
	}

	async listProjectEvaluations(
		projectId: string,
	): Promise<ProjectValueEvaluation[]> {
		await this.projects.get(projectId);
		return this.evaluations.findEvaluationsByProjectId(projectId);
	}

	async getEvaluation(evaluationId: string): Promise<ProjectValueEvaluation> {
		const evaluation = await this.evaluations.findEvaluationById(evaluationId);
		if (!evaluation) {
			throw new HttpError(404, "Evaluation not found.");
		}
		return evaluation;
	}

	async getActivityEvents(
		evaluationId: string,
	): Promise<EvaluationActivityEvent[]> {
		const evaluation = await this.evaluations.findEvaluationById(evaluationId);
		if (!evaluation) {
			throw new HttpError(404, "Evaluation not found.");
		}
		return this.evaluations.findActivityEventsByEvaluationId(evaluationId);
	}

	async getImprovements(evaluationId: string) {
		const evaluation = await this.evaluations.findEvaluationById(evaluationId);
		if (!evaluation) {
			throw new HttpError(404, "Evaluation not found.");
		}
		return this.evaluations.findImprovementsByEvaluationId(evaluationId);
	}
}

import { randomUUID } from "node:crypto";
import {
	improvementRequestSchema,
	type Gap,
	type ImprovementRequest,
	type ProjectValueEvaluation,
} from "../../../shared/schemas/evaluation.schema";

function taskTypeForGap(gap: Gap): ImprovementRequest["taskType"] {
	if (gap.kind === "documentation-gap") return "docs";
	if (gap.kind === "runtime-gap" || gap.kind === "evidence-gap") {
		return "evidence";
	}
	if (gap.affectedDimensions.includes("security")) return "security";
	if (gap.affectedDimensions.includes("agentUsability")) {
		return "agent-usability";
	}
	return "feature";
}

function verificationForGap(gap: Gap): string[] {
	if (gap.kind === "documentation-gap") {
		return ["bun run typecheck", "bun run format:check"];
	}
	if (gap.kind === "runtime-gap" || gap.kind === "evidence-gap") {
		return ["bun run verify"];
	}
	return ["bun run typecheck", "bun run test"];
}

function promptForGap(gap: Gap): string {
	return [
		`次のギャップが検出されています: ${gap.title}。`,
		`理由: ${gap.rationale}`,
		`影響する評価軸: ${gap.affectedDimensions.join("、")}。`,
		"このギャップを閉じる最小の変更を実装し、その後に検証コマンドを実行してください。",
	].join("\n");
}

export function generateImprovementRequests(
	evaluation: ProjectValueEvaluation,
): ImprovementRequest[] {
	return evaluation.gapsTo100
		.slice()
		.sort((a, b) => {
			const aGain = a.expectedScoreGain + a.expectedConfidenceGain * 20;
			const bGain = b.expectedScoreGain + b.expectedConfidenceGain * 20;
			return bGain - aGain;
		})
		.slice(0, 6)
		.map((gap, index) =>
			improvementRequestSchema.parse({
				id: randomUUID(),
				evaluationId: evaluation.id,
				title: gap.title,
				reason: gap.rationale,
				sourceGapIds: [gap.id],
				sourceDimensionKeys: gap.affectedDimensions,
				expectedScoreGain: gap.expectedScoreGain,
				expectedConfidenceGain: gap.expectedConfidenceGain,
				complexity: gap.kind === "runtime-gap" ? 1 : 2,
				priority: index + 1,
				taskType: taskTypeForGap(gap),
				prompt: promptForGap(gap),
				acceptanceCriteria: [
					"ギャップが最小かつレビューしやすい変更で解消されている。",
					"次回評価で改善を検出できるように、根拠が追加または更新されている。",
					"検証コマンドが成功している、または失敗理由が記録されている。",
				],
				verificationCommands: verificationForGap(gap),
				createdAt: new Date().toISOString(),
			}),
		);
}

