	});
}

function toEvaluationActivityEvent(
	row: typeof evaluationActivityEvents.$inferSelect,
): EvaluationActivityEvent {
	return evaluationActivityEventSchema.parse({
		id: row.id,
		seq: row.seq,
		phase: row.phase,
		level: row.level,
		source: row.source,
		message: row.message,
