					complexity: improvement.complexity,
					priority: improvement.priority,
					taskType: improvement.taskType,
					prompt: improvement.prompt,
					acceptanceCriteriaJson: JSON.stringify(
						improvement.acceptanceCriteria,
					),
					verificationCommandsJson: JSON.stringify(
						improvement.verificationCommands,
					),
					createdAt: new Date(improvement.createdAt),
				})),
			)
			.returning();
		return rows.map(toImprovementRequest);
	}

	async createActivityEvents(
		evaluationId: string,
		activityEvents: EvaluationActivityEvent[],
	): Promise<EvaluationActivityEvent[]> {
		if (activityEvents.length === 0) return [];
		const rows = await this.db
			.insert(evaluationActivityEvents)
			.values(
				activityEvents.map((event) => ({
					id: event.id,
					evaluationId,
					seq: event.seq,
					phase: event.phase,
					level: event.level,
					source: event.source,
					message: event.message,
					status: event.status,
					payloadJson:
						event.payload === undefined ? null : JSON.stringify(event.payload),
					createdAt: new Date(event.createdAt),
				})),
			)
			.returning();
		return rows.map(toEvaluationActivityEvent);
	}

	async createEvaluationRun(params: {
		bundle: EvaluationBundle;
		evaluation: ProjectValueEvaluation;
		rawOutput: unknown;
		improvements: ImprovementRequest[];
		activityEvents?: EvaluationActivityEvent[];
	}): Promise<{
		bundle: EvaluationBundle;
		evaluation: ProjectValueEvaluation;
		improvements: ImprovementRequest[];
		activityEvents: EvaluationActivityEvent[];
	}> {
		return this.db.transaction((tx) => {
			const bundleRow = tx
				.insert(evaluationBundles)
				.values({
					id: params.bundle.id,
					projectId: params.bundle.projectId,
					evidenceLevel: params.bundle.evidenceLevel,
					projectRoot: params.bundle.projectRoot,
					inputsJson: JSON.stringify(params.bundle.inputs),
					inspectedInputsJson: JSON.stringify(params.bundle.inspectedInputs),
					missingInputsJson: JSON.stringify(params.bundle.missingInputs),
					notVerifiedJson: JSON.stringify(params.bundle.notVerified),
					createdAt: new Date(params.bundle.createdAt),
				})
				.returning()
				.get();
			const evaluationRow = tx
				.insert(projectEvaluations)
				.values({
					id: params.evaluation.id,
					projectId: params.evaluation.projectId,
					bundleId: params.evaluation.bundleId,
					score: params.evaluation.score,
					idealScore: params.evaluation.idealScore,
					overallConfidence: confidenceToStored(
						params.evaluation.overallConfidence,
					),
					evidenceLevel: params.evaluation.evidenceLevel,
					summary: params.evaluation.summary,
					dimensionsJson: JSON.stringify(params.evaluation.dimensions),
					strengthsJson: JSON.stringify(params.evaluation.strengths),
					gapsTo100Json: JSON.stringify(params.evaluation.gapsTo100),
					sourceInspectionsJson: JSON.stringify(
						params.evaluation.sourceInspections,
					),
					notVerifiedJson: JSON.stringify(params.evaluation.notVerified),
					nextEvidenceToCollectJson: JSON.stringify(
						params.evaluation.nextEvidenceToCollect,
					),
					previousScore: params.evaluation.previousScore,
					scoreDelta: params.evaluation.scoreDelta,
					previousConfidence:
						params.evaluation.previousConfidence === undefined
							? undefined
							: confidenceToStored(params.evaluation.previousConfidence),
					confidenceDelta:
						params.evaluation.confidenceDelta === undefined
							? undefined
							: ratioDeltaToStored(params.evaluation.confidenceDelta),
					rawOutputJson: JSON.stringify(params.rawOutput),
					createdAt: new Date(params.evaluation.createdAt),
				})
				.returning()
				.get();
			const improvementRows =
				params.improvements.length === 0
					? []
					: tx
							.insert(improvementRequests)
							.values(
								params.improvements.map((improvement) => ({
									id: improvement.id,
									evaluationId: improvement.evaluationId,
									title: improvement.title,
									reason: improvement.reason,
									sourceGapIdsJson: JSON.stringify(improvement.sourceGapIds),
									sourceDimensionKeysJson: JSON.stringify(
										improvement.sourceDimensionKeys,
									),
									expectedScoreGain: improvement.expectedScoreGain,
									expectedConfidenceGain: confidenceToStored(
										improvement.expectedConfidenceGain,
									),
									complexity: improvement.complexity,
									priority: improvement.priority,
									taskType: improvement.taskType,
									prompt: improvement.prompt,
									acceptanceCriteriaJson: JSON.stringify(
										improvement.acceptanceCriteria,
									),
									verificationCommandsJson: JSON.stringify(
										improvement.verificationCommands,
									),
									createdAt: new Date(improvement.createdAt),
								})),
							)
							.returning()
							.all();
			const activityRows =
				params.activityEvents?.length === 0 || !params.activityEvents
					? []
					: tx
							.insert(evaluationActivityEvents)
							.values(
								params.activityEvents.map((event) => ({
									id: event.id,
									evaluationId: params.evaluation.id,
									seq: event.seq,
									phase: event.phase,
									level: event.level,
									source: event.source,
									message: event.message,
									status: event.status,
									payloadJson:
										event.payload === undefined
											? null
											: JSON.stringify(event.payload),
									createdAt: new Date(event.createdAt),
								})),
							)
							.returning()
							.all();
			return {
				bundle: toEvaluationBundle(bundleRow),
				evaluation: toProjectValueEvaluation(evaluationRow),
				improvements: improvementRows.map(toImprovementRequest),
				activityEvents: activityRows.map(toEvaluationActivityEvent),
			};
		});
	}

	async findLatestEvaluation(
		projectId: string,
	): Promise<ProjectValueEvaluation | null> {
		const row = await this.db.query.projectEvaluations.findFirst({
			where: eq(projectEvaluations.projectId, projectId),
			orderBy: [desc(projectEvaluations.createdAt)],
		});
		return row ? toProjectValueEvaluation(row) : null;
	}

	async findEvaluationsByProjectId(
		projectId: string,
	): Promise<ProjectValueEvaluation[]> {
		const rows = await this.db.query.projectEvaluations.findMany({
			where: eq(projectEvaluations.projectId, projectId),
			orderBy: [desc(projectEvaluations.createdAt)],
		});
		return rows.map(toProjectValueEvaluation);
	}

	async findEvaluationById(
		evaluationId: string,
	): Promise<ProjectValueEvaluation | null> {
		const row = await this.db.query.projectEvaluations.findFirst({
			where: eq(projectEvaluations.id, evaluationId),
		});
		return row ? toProjectValueEvaluation(row) : null;
	}

	async findActivityEventsByEvaluationId(
		evaluationId: string,
	): Promise<EvaluationActivityEvent[]> {
		const rows = await this.db.query.evaluationActivityEvents.findMany({
			where: eq(evaluationActivityEvents.evaluationId, evaluationId),
			orderBy: [asc(evaluationActivityEvents.seq)],
		});
		return rows.map(toEvaluationActivityEvent);
	}

	async findImprovementsByEvaluationId(
		evaluationId: string,
	): Promise<ImprovementRequest[]> {
		const rows = await this.db.query.improvementRequests.findMany({
			where: eq(improvementRequests.evaluationId, evaluationId),
			orderBy: [asc(improvementRequests.priority)],
		});
		return rows.map(toImprovementRequest);
	}
}

import { and, desc, eq, isNull } from "drizzle-orm";
import type { BunSQLiteDatabase } from "drizzle-orm/bun-sqlite";
import {
	projectProfileSchema,
	type ProjectProfile,
	type ProjectProfileCreate,
} from "../../../shared/schemas/project.schema";
import { projectProfiles } from "../../db/schema";
import type * as schema from "../../db/schema";

const parseJsonArray = (value: string): string[] => {
	const parsed = JSON.parse(value) as unknown;
	return Array.isArray(parsed) ? parsed.map(String) : [];
};

const toIso = (value: Date): string => value.toISOString();

function toProjectProfile(
	row: typeof projectProfiles.$inferSelect,
): ProjectProfile {
	return projectProfileSchema.parse({
		id: row.id,
		name: row.name,
		rootPath: row.rootPath,
		ideal: row.ideal,
		primaryAudience: row.primaryAudience,
		targetWorkflow: row.targetWorkflow,
		nonGoals: parseJsonArray(row.nonGoalsJson),
		dimensions: parseJsonArray(row.dimensionsJson),
		createdAt: toIso(row.createdAt),
		updatedAt: toIso(row.updatedAt),
	});
}

export class ProjectRepository {
	constructor(private readonly db: BunSQLiteDatabase<typeof schema>) {}

	async create(input: ProjectProfileCreate): Promise<ProjectProfile> {
		const now = new Date();
		const [row] = await this.db
			.insert(projectProfiles)
			.values({
				name: input.name,
				rootPath: input.rootPath,
				ideal: input.ideal,
				primaryAudience: input.primaryAudience,
				targetWorkflow: input.targetWorkflow,
				nonGoalsJson: JSON.stringify(input.nonGoals),
				dimensionsJson: JSON.stringify(input.dimensions),
				createdAt: now,
				updatedAt: now,
			})
			.returning();
		return toProjectProfile(row);
	}

	async update(
		id: string,
		input: ProjectProfileCreate,
	): Promise<ProjectProfile | null> {
		const now = new Date();
		const [row] = await this.db
			.update(projectProfiles)
			.set({
				name: input.name,
				rootPath: input.rootPath,
				ideal: input.ideal,
				primaryAudience: input.primaryAudience,
				targetWorkflow: input.targetWorkflow,
				nonGoalsJson: JSON.stringify(input.nonGoals),
				dimensionsJson: JSON.stringify(input.dimensions),
				updatedAt: now,
			})
			.where(and(eq(projectProfiles.id, id), isNull(projectProfiles.deletedAt)))
			.returning();
		return row ? toProjectProfile(row) : null;
	}

	async findById(id: string): Promise<ProjectProfile | null> {
		const row = await this.db.query.projectProfiles.findFirst({
			where: and(eq(projectProfiles.id, id), isNull(projectProfiles.deletedAt)),
		});
		return row ? toProjectProfile(row) : null;
	}

	async list(): Promise<ProjectProfile[]> {
		const rows = await this.db.query.projectProfiles.findMany({
			where: isNull(projectProfiles.deletedAt),
			orderBy: [desc(projectProfiles.updatedAt)],
		});
		return rows.map(toProjectProfile);
	}

	async findByRootPath(rootPath: string): Promise<ProjectProfile | null> {
		const row = await this.db.query.projectProfiles.findFirst({
			where: and(
				eq(projectProfiles.rootPath, rootPath),
				isNull(projectProfiles.deletedAt),
			),
		});
		return row ? toProjectProfile(row) : null;
	}

	async softDelete(id: string): Promise<ProjectProfile | null> {
		const now = new Date();
		const [row] = await this.db
			.update(projectProfiles)
			.set({
				deletedAt: now,
				updatedAt: now,
			})
			.where(and(eq(projectProfiles.id, id), isNull(projectProfiles.deletedAt)))
			.returning();
		return row ? toProjectProfile(row) : null;
	}
}

import { createInterface } from "node:readline/promises";
import { stdin as input, stdout as output } from "node:process";
import { readAppEnv } from "../app/env";
import { createDbConnection } from "../db";
import { AuthService } from "../modules/auth/auth.service";

type CliArgs = {
	email?: string;
	name?: string;
	password?: string;
	passwordFromStdin: boolean;
};

function parseArgs(argv: string[]): CliArgs {
	const args: CliArgs = { passwordFromStdin: false };
	for (let i = 0; i < argv.length; i += 1) {
		const token = argv[i];
		if (token === "--email") {
			args.email = argv[i + 1];
			i += 1;
			continue;
		}
		if (token === "--name") {
			args.name = argv[i + 1];
			i += 1;
			continue;
		}
		if (token === "--password") {
			args.password = argv[i + 1];
			i += 1;
			continue;
		}
		if (token === "--password-stdin") {
			args.passwordFromStdin = true;
		}
	}
	return args;
}

async function readPassword(args: CliArgs): Promise<string> {
	if (args.password) {
		return args.password;
	}
	if (args.passwordFromStdin) {
		const chunks: Buffer[] = [];
		for await (const chunk of input) {
			chunks.push(Buffer.from(chunk));
		}
		return Buffer.concat(chunks).toString("utf8").trim();
	}

	const rl = createInterface({ input, output });
	try {
		return (await rl.question("Password: ")).trim();
	} finally {
		rl.close();
	}
}

async function main() {
	const args = parseArgs(process.argv.slice(2));
	if (!args.email || !args.name) {
		throw new Error("--email and --name are required.");
	}
	const password = await readPassword(args);
	if (password.length < 8) {
		throw new Error("Password must be at least 8 characters.");
	}

	const env = readAppEnv();
	const db = createDbConnection(env.databaseUrl);
	try {
		const authService = new AuthService(db.db, env);
		const user = await authService.createAdmin({
			email: args.email,
			displayName: args.name,
			password,
		});
		console.log(
			JSON.stringify(
				{
					ok: true,
					user: {
						id: user.id,
						email: user.email,
						displayName: user.displayName,
						role: user.role,
					},
				},
				null,
				2,
			),
		);
	} finally {
		if (db.ownsConnection) {
			db.client.close();
		}
	}
}

await main();

import { getCookie } from "hono/cookie";
import { createMiddleware } from "hono/factory";
import type { AppEnv } from "../app/env";
import { ACCESS_TOKEN_COOKIE_NAME } from "../modules/auth/auth-cookies";
import { verifyAccessToken } from "../modules/auth/token.service";
import { HttpError } from "../modules/auth/errors";
import type { AuthService } from "../modules/auth/auth.service";

type AuthMiddlewareDeps = {
	env: AppEnv;
	authService: AuthService;
};

const unauthorized = new HttpError(401, "Unauthorized");

const resolveToken = (
	authorizationHeader: string | undefined,
	cookieToken?: string,
) => {
	if (authorizationHeader?.startsWith("Bearer ")) {
		return authorizationHeader.slice("Bearer ".length).trim();
	}
	return cookieToken ?? null;
};

export const requireAuth = (deps: AuthMiddlewareDeps) =>
	createMiddleware(async (c, next) => {
		const token = resolveToken(
			c.req.header("Authorization"),
			getCookie(c, ACCESS_TOKEN_COOKIE_NAME),
		);
		if (!token) {
			throw unauthorized;
		}

		const payload = await verifyAccessToken(token, deps.env).catch(() => {
			throw unauthorized;
		});
		const user = await deps.authService.findUserById(payload.userId);
		if (!user?.isActive) {
			throw unauthorized;
		}

		c.set("authUser", {
			userId: user.id,
			email: user.email,
			role: user.role,
		});
		await next();
	});

import type { Context } from "hono";
import { deleteCookie, setCookie } from "hono/cookie";
import type { AppEnv } from "../../app/env";

export const ACCESS_TOKEN_COOKIE_NAME = "access_token";
export const REFRESH_TOKEN_COOKIE_NAME = "refresh_token";

const parseDurationToSeconds = (duration: string): number | undefined => {
	const match = duration.match(/^(\d+)([smhd])$/i);
	if (!match) return undefined;
	const value = Number.parseInt(match[1], 10);
	if (!Number.isFinite(value) || value <= 0) return undefined;
	const unit = match[2]?.toLowerCase();
	switch (unit) {
		case "s":
			return value;
		case "m":
			return value * 60;
		case "h":
			return value * 60 * 60;
		case "d":
			return value * 60 * 60 * 24;
		default:
			return undefined;
	}
};

export const setAuthCookies = (
	c: Context,
	env: AppEnv,
	tokens: { accessToken: string; refreshToken: string },
) => {
	const secure = env.secureCookie;
	const accessMaxAge = parseDurationToSeconds(env.jwtAccessExpiresIn);
	const refreshMaxAge = parseDurationToSeconds(env.jwtRefreshExpiresIn);

	setCookie(c, ACCESS_TOKEN_COOKIE_NAME, tokens.accessToken, {
		httpOnly: true,
		secure,
		sameSite: env.cookieSameSite,
		path: "/",
		...(accessMaxAge ? { maxAge: accessMaxAge } : {}),
	});

	setCookie(c, REFRESH_TOKEN_COOKIE_NAME, tokens.refreshToken, {
		httpOnly: true,
		secure,
		sameSite: env.cookieSameSite,
		path: "/api/auth",
		...(refreshMaxAge ? { maxAge: refreshMaxAge } : {}),
	});
};

export const clearAuthCookies = (c: Context) => {
	deleteCookie(c, ACCESS_TOKEN_COOKIE_NAME, { path: "/" });
	deleteCookie(c, REFRESH_TOKEN_COOKIE_NAME, { path: "/api/auth" });
};

import { eq } from "drizzle-orm";
import type { BunSQLiteDatabase } from "drizzle-orm/bun-sqlite";
import type { AppEnv } from "../../app/env";
import { users } from "../../db/schema";
import type * as schema from "../../db/schema";
import { HttpError } from "./errors";
import { hashPassword, verifyPassword } from "./password";
import {
	consumeRefreshToken,
	generateAccessToken,
	generateRefreshToken,
	revokeRefreshToken,
} from "./token.service";
import {
	userRoleSchema,
	type AuthSessionUser,
	type AuthUser,
	type UserRole,
} from "./types";

type AuthTokensResult = {
	accessToken: string;
	refreshToken: string;
	user: AuthSessionUser;
};

type CreateUserInput = {
	email: string;
	displayName: string;
	password: string;
	role?: UserRole;
};

const normalizeRole = (role: string): UserRole => {
	const parsed = userRoleSchema.safeParse(role);
	return parsed.success ? parsed.data : "member";
};

const toAuthUser = (row: typeof users.$inferSelect): AuthUser => ({
	id: row.id,
	email: row.email,
	passwordHash: row.passwordHash,
	displayName: row.displayName,
	role: normalizeRole(row.role),
	isActive: row.isActive,
	lastLoginAt: row.lastLoginAt,
	createdAt: row.createdAt,
	updatedAt: row.updatedAt,
});

const toSessionUser = (user: AuthUser): AuthSessionUser => ({
	id: user.id,
	email: user.email,
	displayName: user.displayName,
	role: user.role,
});

export class AuthService {
	constructor(
		private readonly db: BunSQLiteDatabase<typeof schema>,
		private readonly env: AppEnv,
	) {}

	async findUserById(userId: string): Promise<AuthUser | null> {
		const row = await this.db.query.users.findFirst({
			where: eq(users.id, userId),
		});
		return row ? toAuthUser(row) : null;
	}

	async findUserByEmail(email: string): Promise<AuthUser | null> {
		const row = await this.db.query.users.findFirst({
			where: eq(users.email, email.toLowerCase()),
		});
		return row ? toAuthUser(row) : null;
	}

	private async issueTokens(user: AuthUser): Promise<AuthTokensResult> {
		const accessToken = await generateAccessToken(
			{
				userId: user.id,
				email: user.email,
				role: user.role,
			},
			this.env,
		);
		const refreshToken = await generateRefreshToken(
			{
				userId: user.id,
				email: user.email,
				role: user.role,
			},
			this.db,
			this.env,
		);
		return {
			accessToken,
			refreshToken,
			user: toSessionUser(user),
		};
	}

	async login(params: {
		email: string;
		password: string;
	}): Promise<AuthTokensResult> {
		const user = await this.findUserByEmail(params.email);
		if (!user?.isActive) {
			throw new HttpError(401, "Invalid email or password.");
		}
		const valid = await verifyPassword(params.password, user.passwordHash);
		if (!valid) {
			throw new HttpError(401, "Invalid email or password.");
		}
		const now = new Date();
		await this.db
			.update(users)
			.set({ lastLoginAt: now, updatedAt: now })
			.where(eq(users.id, user.id));
		const refreshed = await this.findUserById(user.id);
		if (!refreshed) {
			throw new HttpError(404, "User not found.");
		}
		return this.issueTokens(refreshed);
	}

	async refresh(refreshToken: string): Promise<AuthTokensResult> {
		const payload = await consumeRefreshToken(refreshToken, this.db, this.env);
		const user = await this.findUserById(payload.userId);
		if (!user?.isActive) {
			throw new HttpError(401, "User account is inactive or deleted.");
		}
		return this.issueTokens(user);
	}

	async logout(refreshToken?: string): Promise<void> {
		if (!refreshToken) return;
		await revokeRefreshToken(refreshToken, this.db);
	}

	async createAdmin(input: Omit<CreateUserInput, "role">): Promise<AuthUser> {
		const existing = await this.findUserByEmail(input.email);
		if (existing) {
			throw new HttpError(409, "Email already in use.");
		}
		const passwordHash = await hashPassword(input.password);
		const [created] = await this.db
			.insert(users)
			.values({
				email: input.email.toLowerCase(),
				passwordHash,
				displayName: input.displayName,
				role: "admin",
				isActive: true,
			})
			.returning();
		return toAuthUser(created);
	}
}

